package main.rice.node;

import main.rice.obj.APyObj;
import main.rice.obj.PySetObj;

import java.util.ArrayList;
import java.util.HashSet;
import java.util.LinkedHashSet;
import java.util.List;
import java.util.Random;
import java.util.Set;

/**
 * Generates Python set values.
 *
 * @param <InnerType> type of set elements
 */
public class PySetNode<InnerType extends APyObj> extends AIterablePyNode<PySetObj<InnerType>> {
    private final Random rng;

    public PySetNode(APyNode<InnerType> leftChild) {
        super(leftChild, null);
        this.rng = new Random();
    }

    @Override
    @SuppressWarnings("unchecked")
    public Set<PySetObj<InnerType>> genExVals() {
        Set<PySetObj<InnerType>> retval = new HashSet<>();
        List<InnerType> elems = new ArrayList<>((Set<InnerType>) this.leftChild.genExVals());

        for (Integer len : this.exDomain) {
            buildSets(elems, 0, len, new ArrayList<>(), retval);
        }
        return retval;
    }

    @Override
    @SuppressWarnings("unchecked")
    public PySetObj<InnerType> genRandVal() {
        int len = this.ranDomain.get(this.rng.nextInt(this.ranDomain.size()));
        APyNode<InnerType> child = (APyNode<InnerType>) this.leftChild;
        Set<InnerType> retval = new LinkedHashSet<>();

        int attempts = 0;
        int maxAttempts = Math.max(200, len * 200);
        while (retval.size() < len && attempts < maxAttempts) {
            retval.add(child.genRandVal());
            attempts++;
        }

        return new PySetObj<>(retval);
    }

    private void buildSets(List<InnerType> elems, int start, int remaining,
                           List<InnerType> cur, Set<PySetObj<InnerType>> out) {
        if (remaining < 0) {
            return;
        }
        if (remaining == 0) {
            out.add(new PySetObj<>(new HashSet<>(cur)));
            return;
        }
        for (int idx = start; idx < elems.size(); idx++) {
            cur.add(elems.get(idx));
            buildSets(elems, idx + 1, remaining - 1, cur, out);
            cur.remove(cur.size() - 1);
        }
    }
}
